5	describe("MHPCO Claim Office", () => {
6	  describe("quotes: basics", () => {
7	    it("should return premium 5 for a quote with an empty item list (processing fee only)", () => {
8	      const scenario = {
9	        customer: { yearsWithMHPCO: 0 },
10	        steps: [{ op: "quote", items: [] }],
11	      };
12	
13	      expect(processScenario(scenario)).toEqual({ results: [{ premium: 5 }] });
14	    });
15	    it("should return premium 115 for a single sword (100 base + 10% first-insurance + 5 fee)", () => {
16	      const scenario = {
17	        customer: { yearsWithMHPCO: 0 },
18	        steps: [{ op: "quote", items: [{ type: "sword" }] }],
19	      };
20	
21	      expect(processScenario(scenario)).toEqual({ results: [{ premium: 115 }] });
22	    });
23	    it("should return premium 71 for a single amulet (60 base)", () => {
24	      const scenario = {
25	        customer: { yearsWithMHPCO: 0 },
26	        steps: [{ op: "quote", items: [{ type: "amulet" }] }],
27	      };
28	
29	      expect(processScenario(scenario)).toEqual({ results: [{ premium: 71 }] });
30	    });
31	    it("should return premium 93 for a single staff (80 base)", () => {
32	      const scenario = {
33	        customer: { yearsWithMHPCO: 0 },
34	        steps: [{ op: "quote", items: [{ type: "staff" }] }],
35	      };
36	
37	      expect(processScenario(scenario)).toEqual({ results: [{ premium: 93 }] });
38	    });
39	    it("should return premium 49 for a single potion (40 base)", () => {
40	      const scenario = {
41	        customer: { yearsWithMHPCO: 0 },
42	        steps: [{ op: "quote", items: [{ type: "potion" }] }],
43	      };
44	
45	      expect(processScenario(scenario)).toEqual({ results: [{ premium: 49 }] });
46	    });
47	    it.todo("should return one result per step in the scenario");
48	  });
49	
50	  describe("quotes: components and block", () => {
51	    it.todo("should return premium 33 for a single rune (25 base, final premium rounded up)");
52	    it.todo("should return premium 60 for 2 runes (50 base, no block)");
53	    it.todo("should return premium 71 for exactly 3 runes (block rate of 60 base)");
54	    it.todo("should return premium 115 for 4 runes (100 base, block requires exactly 3)");
55	    it.todo("should return premium 198 for 7 runes (175 base, no block)");
56	    it.todo("should return premium 88 for 2 runes and 1 moonstone (75 base, no block across types)");
57	    it.todo("should return premium 137 for 3 runes and 3 moonstones (two blocks, 120 base)");
58	  });
59	
60	  describe("quotes: item modifiers", () => {
61	    it.todo("should add 50% of the item base premium for a cursed item (cursed sword -> 165)");
62	    it.todo("should add 30% of the item base premium for enchantment level 5 or higher (sword ench 5 -> 145)");
63	  });
64	
65	  describe("quotes: policy modifiers", () => {
66	    it.todo("should subtract 20% loyalty discount for customers with 2 or more years (sword, 2 years -> 95)");
67	    it.todo("should subtract 15% follow-up discount on each quote after the first in the scenario (second sword quote -> 100)");
68	  });
69	
70	  describe("quotes: integration examples", () => {
71	    it.todo("should return premium 165 for a newcomer with a cursed steel sword of enchantment 3");
72	    it.todo("should return premium 160 for a 3-year customer's second quote with a cursed steel sword of enchantment 7");
73	  });
74	
75	  describe("claims: payouts", () => {
76	    it.todo("should pay damage minus 100 deductible for a standard item (steel sword ench 3, damage 500 -> payout 400)");
77	    it.todo("should pay 100 for a rune damaged at 200");
78	    it.todo("should reimburse 50% of the damage before deductible for enchantment 8 or higher (steel sword ench 9, damage 1000 -> payout 400)");
