83	
84	  describe("claims: deductible per damaged item", () => {
85	    it.todo("should apply the deductible once per damaged item (sword damage 500 + amulet damage 300 -> payout 600)");
86	    it.todo("should apply a separate deductible to each damage entry of the same type (two insured swords, two sword damage entries)");
87	  });
88	
89	  describe("claims: payout cap", () => {
90	    it.todo("should report remainingCap as twice the insurance sum minus the payout (sword policy, claim 1500 -> payout 1400, remainingCap 600)");
